<?php
namespace Tests\Feature;
use App\Services\IdCodec;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Tests\TestCase;
class FinalFlowTest extends TestCase {use RefreshDatabase;protected bool $seed=true;public function test_web_student_flow_is_one_question_per_screen_and_submit_is_idempotent():void{$ids=app(IdCodec::class);$j=$ids->encode(1);$sid=$ids->encode(1);$this->post('/login',['username'=>'siswa','password'=>'siswa123'])->assertRedirectContains('/dashboard?auth_refresh=');$this->get('/dashboard')->assertRedirect('/vue/dashboard/siswa');$this->post("/ujian/$j/mulai",['token'=>'LATIHAN'])->assertRedirect("/ujian/sesi/$sid?nomor=1");$this->get("/ujian/sesi/$sid?nomor=1")->assertOk()->assertSee('Soal 1')->assertDontSee('Berapakah hasil dari 5 x 3?');$q=DB::table('bank_soals')->first();$o=DB::table('opsi_jawabans')->where(['bank_soal_id'=>$q->id,'is_benar'=>true])->first();$this->post("/ujian/sesi/$sid/simpan",['soal_hash'=>$ids->encode($q->id),'opsi_hash'=>$ids->encode($o->id),'next_number'=>2])->assertRedirect("/ujian/sesi/$sid?nomor=2");$this->post("/ujian/sesi/$sid/selesai")->assertRedirect("/ujian/sesi/$sid/hasil");$this->post("/ujian/$j/mulai",['token'=>'LATIHAN'])->assertRedirect("/ujian/sesi/$sid/hasil");}public function test_api_jwt_login_question_heartbeat_sync_and_submit():void{$id=app(IdCodec::class)->encode(1);$login=$this->postJson('/api/v1/auth/login',['username'=>'siswa','password'=>'siswa123'])->assertOk()->json('data.token');$h=['Authorization'=>'Bearer '.$login];$this->withHeaders($h)->getJson('/api/v1/auth/me')->assertOk()->assertJsonPath('data.username','siswa');$this->withHeaders($h)->postJson("/api/v1/ujian/$id/masuk",['token'=>'LATIHAN'])->assertOk()->assertJsonPath('data.session_hash',$id);$question=$this->withHeaders($h)->getJson("/api/v1/ujian/sesi/$id/soal?nomor=1")->assertOk()->assertJsonMissing(['is_benar'=>true])->json('data.soal');$this->withHeaders($h)->postJson("/api/v1/ujian/sesi/$id/sync",['answers'=>[['soal_hash'=>$question['hashid'],'opsi_hash'=>$question['opsi'][1]['hashid']]]])->assertOk()->assertJsonPath('data.synced',1);$this->withHeaders($h)->postJson("/api/v1/ujian/sesi/$id/ping")->assertOk();$this->withHeaders($h)->postJson("/api/v1/ujian/sesi/$id/submit")->assertOk();}}
